// TypeScript implementation for Generic Constraints
interface GenericConstraintsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processGenericConstraints(item: GenericConstraintsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processGenericConstraints({ id: 1, title: 'Generic Constraints', status: 'active' }));

